333	- [ ] **Step 3: Implement `runWebSearch` (+ shared internals) in `anthropic-client.ts`**
334	
335	```ts
336	import type Anthropic from '@anthropic-ai/sdk';
337	
338	export interface CallOpts {
339	  model: string;
340	  maxTokens: number;
341	}
342	
343	export interface WebSearchHit {
344	  title: string;
345	  url: string;
346	  age?: string;
347	}
348	
349	export interface WebSearchOutput {
350	  query: string;
351	  results: WebSearchHit[];
352	  summary?: string;
353	}
354	
355	const MAX_PAUSE_ITERATIONS = 4;
356	
357	// Drive a server-tool conversation to completion, accumulating every
358	// content block across pause_turn continuations. Generic over both web
359	// tools — the caller supplies the tool definition and the user prompt.
360	async function collectBlocks(
361	  client: Anthropic,
362	  opts: CallOpts,
363	  tool: Record<string, unknown>,
364	  userText: string,
365	): Promise<Array<Record<string, unknown>>> {
366	  const messages: Array<Record<string, unknown>> = [{ role: 'user', content: userText }];
367	  const blocks: Array<Record<string, unknown>> = [];
368	  for (let i = 0; i < MAX_PAUSE_ITERATIONS; i += 1) {
369	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
370	    const res: any = await client.messages.create({
371	      model: opts.model,
372	      max_tokens: opts.maxTokens,
373	      tools: [tool],
374	      messages,
375	      // eslint-disable-next-line @typescript-eslint/no-explicit-any
376	    } as any);
377	    const content: Array<Record<string, unknown>> = Array.isArray(res?.content) ? res.content : [];
378	    blocks.push(...content);
379	    if (res?.stop_reason !== 'pause_turn') break;
380	    messages.push({ role: 'assistant', content });
381	  }
382	  return blocks;
383	}
384	
385	export async function runWebSearch(
386	  client: Anthropic,
387	  opts: CallOpts,
388	  query: string,
389	): Promise<WebSearchOutput> {
390	  const blocks = await collectBlocks(
391	    client,
392	    opts,
393	    { type: 'web_search_20250305', name: 'web_search', max_uses: 1 },
394	    `Search the web for: ${query}\nUse the web_search tool once, then stop.`,
395	  );
396	
397	  const resultBlock = blocks.find((b) => b?.type === 'web_search_tool_result') as
398	    | { content?: unknown }
399	    | undefined;
400	  const rbContent = resultBlock?.content;
401	  if (resultBlock !== undefined && !Array.isArray(rbContent)) {
402	    const code = (rbContent as { error_code?: string } | undefined)?.error_code ?? 'unknown';
403	    throw new Error(`web_search failed: ${code}`);
404	  }
405	
406	  const hits: WebSearchHit[] = Array.isArray(rbContent)
407	    ? (rbContent as Array<Record<string, unknown>>)
408	        .filter((r) => r?.type === 'web_search_result')
409	        .map((r) => ({
410	          title: String(r.title ?? ''),
411	          url: String(r.url ?? ''),
