  bus.registerService<{ input?: unknown }, WebSearchOutput>(
    'tool:execute:web_search',
    PLUGIN_NAME,
    async (_ctx, call) => {
      const input = (call?.input ?? {}) as { query?: unknown };
      const query = typeof input.query === 'string' ? input.query.trim() : '';
