    const extract = await bus.call('tool:execute:web_extract', ctx(), { id: 'c2', name: 'web_extract', input: { url: 'https://a.com' } });
    expect(extract).toMatchObject({ url: 'https://a.com', title: 'A', text: 'hello' });
  });
});
